PREFIX dcat: <http://www.w3.org/ns/dcat#>
PREFIX dct: <http://purl.org/dc/terms/>
PREFIX bif: <http://www.openlinksw.com/schemas/bif#>

SELECT (COUNT(DISTINCT ?dataset) AS ?count)
WHERE {
  ?dataset a dcat:Dataset ;
           dct:title ?title .
  ?title bif:contains "'violence' OR 'violenza' OR 'violencia' OR 'gewalt' OR 'violência'"
}

SELECT DISTINCT ?item ?itemLabel ?typeLabel WHERE {
  SERVICE wikibase:mwapi {
    bd:serviceParam wikibase:api "EntitySearch" ;
                    wikibase:endpoint "www.wikidata.org" ;
                    mwapi:search "MTN Group" ;
                    mwapi:language "en" .
    ?item wikibase:apiOutputItem mwapi:item .
  }
  ?item wdt:P31 ?type .
  FILTER(?type IN (wd:Q4830453, wd:Q6881511, wd:Q891723, wd:Q161726, wd:Q778575))
  SERVICE wikibase:label { bd:serviceParam wikibase:language "en" . }
} LIMIT 5

PREFIX dcat: <http://www.w3.org/ns/dcat#>
PREFIX dcterms: <http://purl.org/dc/terms/>
PREFIX adms: <http://www.w3.org/ns/adms#>

SELECT ?dataset ?title ?issued ?modified ?format
WHERE {
  ?dataset dcat:catalog <http://data.europa.eu/88u/catalogue/data-gov-gr> ;
           dcterms:title ?title .
  OPTIONAL { ?dataset dcterms:issued ?issued }
  OPTIONAL { ?dataset dcterms:modified ?modified }
  FILTER(LANG(?title) = "en" || LANG(?title) = "")
}
ORDER BY DESC(?modified)
LIMIT 15

PREFIX dcat: <http://www.w3.org/ns/dcat#>

SELECT ?dataset ?theme
WHERE {
  ?dataset a dcat:Dataset ;
           dcat:theme ?theme .
}
LIMIT 10

PREFIX dcat: <http://www.w3.org/ns/dcat#>
PREFIX dct: <http://purl.org/dc/terms/>

SELECT (COUNT(DISTINCT ?dataset) AS ?count)
WHERE {
  ?dataset a dcat:Dataset ;
           dcat:keyword "violence"@en
}

PREFIX dct: <http://purl.org/dc/terms/>
SELECT ?regulation ?title WHERE {
  VALUES ?regulation { <http://data.europa.eu/eli/reg/2022/262> }
  ?regulation dct:title ?title .
}
LIMIT 10

SELECT ?title ?description ?publisher WHERE {
  ?dataset a dcat:Dataset ;
    dct:title ?title ;
    dct:publisher ?pub .
  ?pub foaf:name ?publisher .
  FILTER(lang(?title) = "en")
  FILTER(CONTAINS(LCASE(str(?title)), "civic education") || CONTAINS(LCASE(str(?title)), "environmental literacy") || CONTAINS(LCASE(str(?title)), "sustainability education youth"))
}
LIMIT 10

PREFIX dcat: <http://www.w3.org/ns/dcat#>
PREFIX dcterms: <http://purl.org/dc/terms/>

SELECT ?datasetURI ?title ?modified
WHERE {
  <http://data.europa.eu/88u/catalogue/data-gov-gr> dcat:dataset ?datasetURI .
  ?datasetURI dcterms:title ?title .
  OPTIONAL { ?datasetURI dcterms:modified ?modified }
  FILTER(LANG(?title) = "en" || LANG(?title) = "")
}
ORDER BY DESC(?modified)

PREFIX dct: <http://purl.org/dc/terms/>
PREFIX dcat: <http://www.w3.org/ns/dcat#>
PREFIX foaf: <http://xmlns.com/foaf/0.1/>

SELECT ?dataset ?title ?role ?publisher_name WHERE {
  ?agent dct:identifier "c_l219" .
  ?dataset ?role ?agent .
  OPTIONAL { ?dataset dct:title ?title . FILTER(LANG(?title) = "it") }
  OPTIONAL { ?agent foaf:name ?publisher_name }
}
